import React from "react";

import styles from "./BlinkText.module.css";

type BlinkTrigger = "mount" | "hover" | "always";

export interface BlinkTextProps extends React.HTMLAttributes<HTMLSpanElement> {
  children: React.ReactNode;
  trigger?: BlinkTrigger;
  durationMs?: number;
  iterations?: number | "infinite";
  delayMs?: number;
  dimOpacity?: number;
}

export function BlinkText({
  children,
  trigger = "hover",
  durationMs = 420,
  iterations = 3,
  delayMs = 0,
  dimOpacity = 0.12,
  className = "",
  style,
  ...props
}: BlinkTextProps) {
  const mergedStyle = {
    ...style,
    ["--blink-duration" as string]: `${durationMs}ms`,
    ["--blink-iterations" as string]:
      iterations === "infinite" ? "infinite" : String(iterations),
    ["--blink-delay" as string]: `${delayMs}ms`,
    ["--blink-dim-opacity" as string]: String(dimOpacity),
  } as React.CSSProperties;

  return (
    <span
      className={`${styles.root} ${styles[trigger]} ${className}`.trim()}
      style={mergedStyle}
      {...props}
    >
      {children}
    </span>
  );
}

.root {
  display: inline-flex;
  align-items: center;
}

.mount {
  animation: blinkText var(--blink-duration, 420ms) steps(2, end)
    var(--blink-delay, 0ms) var(--blink-iterations, 3);
}

.always {
  animation: blinkText var(--blink-duration, 420ms) steps(2, end)
    var(--blink-delay, 0ms) infinite;
}

.hover:hover {
  animation: blinkText var(--blink-duration, 420ms) steps(2, end)
    var(--blink-delay, 0ms) var(--blink-iterations, 3);
}

@keyframes blinkText {
  0%,
  100% {
    opacity: 1;
  }

  20%,
  40%,
  60%,
  80% {
    opacity: var(--blink-dim-opacity, 0.12);
  }

  30%,
  50%,
  70%,
  90% {
    opacity: 1;
  }
}
